// ─────────────────────────────────────────────────────────────────────────────
//  HeroSection.jsx  — drop-in replacement for the inline hero block
//  Usage: <HeroSection />
// ─────────────────────────────────────────────────────────────────────────────

export function HeroSection() {
  const trending = ['Product Designer', 'Frontend Engineer', 'Remote', 'AI / ML', 'Senior']

  return (
    <section
      style={{
        fontFamily: "'Playfair Display', Georgia, serif",
        background: 'linear-gradient(135deg, #2c1f14 0%, #4a3728 55%, #6b4f38 100%)',
        position: 'relative',
        overflow: 'hidden',
        minHeight: '100vh',
        display: 'flex',
        alignItems: 'center',
        padding: '0 48px',
      }}
    >
      {/* ── Decorative background layers ── */}
      <div style={{
        position: 'absolute', inset: 0,
        backgroundImage: 'radial-gradient(circle at 20% 50%, rgba(212,196,181,0.08) 0%, transparent 60%), radial-gradient(circle at 80% 20%, rgba(224,216,207,0.06) 0%, transparent 50%)',
        pointerEvents: 'none',
      }} />

      {/* Fine dot grid */}
      <div style={{
        position: 'absolute', inset: 0, opacity: 0.06,
        backgroundImage: 'radial-gradient(#e0d8cf 1px, transparent 1px)',
        backgroundSize: '28px 28px',
        pointerEvents: 'none',
      }} />

      {/* Glowing orbs */}
      <div style={{
        position: 'absolute', top: '-80px', right: '-80px',
        width: '340px', height: '340px',
        borderRadius: '50%',
        background: 'radial-gradient(circle, rgba(212,196,181,0.18) 0%, transparent 70%)',
        filter: 'blur(40px)',
        pointerEvents: 'none',
      }} />
      <div style={{
        position: 'absolute', bottom: '-60px', left: '5%',
        width: '260px', height: '260px',
        borderRadius: '50%',
        background: 'radial-gradient(circle, rgba(107,79,56,0.35) 0%, transparent 70%)',
        filter: 'blur(50px)',
        pointerEvents: 'none',
      }} />

      {/* Thin vertical accent line */}
      <div style={{
        position: 'absolute', left: '0', top: '15%', bottom: '15%',
        width: '3px',
        background: 'linear-gradient(to bottom, transparent, rgba(212,196,181,0.5), transparent)',
      }} />

      {/* ── Content ── */}
      <div style={{ position: 'relative', zIndex: 1, maxWidth: '520px', width: '100%' }}>

        {/* Eyebrow badge */}
        <div style={{
          display: 'inline-flex', alignItems: 'center', gap: '8px',
          padding: '6px 14px',
          borderRadius: '100px',
          background: 'rgba(212,196,181,0.10)',
          border: '1px solid rgba(212,196,181,0.20)',
          marginBottom: '28px',
        }}>
          <span style={{
            width: '7px', height: '7px', borderRadius: '50%',
            background: '#d4b896',
            boxShadow: '0 0 8px rgba(212,184,150,0.8)',
            animation: 'pulse 2s infinite',
          }} />
          <style>{`@keyframes pulse { 0%,100%{opacity:1}50%{opacity:.4} }`}</style>
          <span style={{
            color: '#d4b896', fontSize: '11px', fontFamily: "'DM Sans', sans-serif",
            fontWeight: 600, letterSpacing: '0.08em', textTransform: 'uppercase',
          }}>
            {new Date().toLocaleDateString('en-US', { month: 'long', year: 'numeric' })} · New roles daily
          </span>
        </div>

        {/* Main heading */}
        <h1 style={{
          margin: 0,
          fontSize: 'clamp(42px, 5vw, 64px)',
          fontWeight: 900,
          color: '#f5ede4',
          lineHeight: 1.05,
          letterSpacing: '-0.02em',
        }}>
          Find Your
          <br />
          <span style={{ color: '#d4b896', fontStyle: 'italic' }}>Next</span>
          <br />
          Opportunity.
        </h1>

        {/* Decorative rule */}
        <div style={{
          margin: '24px 0',
          display: 'flex', alignItems: 'center', gap: '12px',
        }}>
          <div style={{ height: '1px', width: '40px', background: 'rgba(212,184,150,0.5)' }} />
          <div style={{ height: '4px', width: '4px', borderRadius: '50%', background: '#d4b896' }} />
          <div style={{ height: '1px', flex: 1, background: 'linear-gradient(to right, rgba(212,184,150,0.3), transparent)' }} />
        </div>

        {/* Subtext */}
        <p style={{
          fontFamily: "'DM Sans', sans-serif",
          color: 'rgba(212,196,181,0.70)',
          fontSize: '15px', lineHeight: 1.7,
          margin: '0 0 32px',
          maxWidth: '400px',
          fontWeight: 400,
        }}>
          Discover roles at the most ambitious companies building the future —
          from seed-stage startups to category-defining giants.
        </p>

        {/* Search row */}
        <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
          {/* Role input */}
          <div style={{
            display: 'flex', alignItems: 'center', gap: '8px',
            background: 'rgba(255,255,255,0.07)',
            border: '1px solid rgba(212,196,181,0.20)',
            borderRadius: '14px',
            padding: '12px 16px',
            width: '200px',
            transition: 'border-color .2s',
          }}
            onFocus={e => e.currentTarget.style.borderColor = 'rgba(212,184,150,0.55)'}
            onBlur={e => e.currentTarget.style.borderColor = 'rgba(212,196,181,0.20)'}
          >
            <svg width="15" height="15" fill="none" stroke="rgba(212,184,150,0.7)" strokeWidth="2" viewBox="0 0 24 24">
              <circle cx="11" cy="11" r="8"/><path strokeLinecap="round" d="M21 21l-4.35-4.35"/>
            </svg>
            <input
              type="text" placeholder="Role or skill..."
              style={{
                background: 'none', border: 'none', outline: 'none',
                color: '#f5ede4', fontSize: '13.5px',
                fontFamily: "'DM Sans', sans-serif", fontWeight: 500,
                width: '100%',
              }}
            />
          </div>

          {/* Location input */}
          <div style={{
            display: 'flex', alignItems: 'center', gap: '8px',
            background: 'rgba(255,255,255,0.07)',
            border: '1px solid rgba(212,196,181,0.20)',
            borderRadius: '14px',
            padding: '12px 16px',
            width: '160px',
          }}>
            <svg width="14" height="14" fill="none" stroke="rgba(212,184,150,0.7)" strokeWidth="2" viewBox="0 0 24 24">
              <path strokeLinecap="round" d="M17.657 16.657L13.414 20.9a2 2 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z"/>
              <path strokeLinecap="round" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z"/>
            </svg>
            <input
              type="text" placeholder="Location..."
              style={{
                background: 'none', border: 'none', outline: 'none',
                color: '#f5ede4', fontSize: '13.5px',
                fontFamily: "'DM Sans', sans-serif", fontWeight: 500,
                width: '100%',
              }}
            />
          </div>

          {/* Search button */}
          <button style={{
            padding: '12px 22px',
            background: 'linear-gradient(135deg, #d4b896 0%, #c4a07a 100%)',
            border: 'none', borderRadius: '14px',
            color: '#2c1f14', fontSize: '13.5px',
            fontFamily: "'DM Sans', sans-serif", fontWeight: 700,
            cursor: 'pointer', letterSpacing: '0.02em',
            boxShadow: '0 4px 20px rgba(196,160,122,0.35)',
            transition: 'transform .15s, box-shadow .15s',
          }}
            onMouseEnter={e => { e.currentTarget.style.transform = 'translateY(-1px)'; e.currentTarget.style.boxShadow = '0 6px 24px rgba(196,160,122,0.45)' }}
            onMouseLeave={e => { e.currentTarget.style.transform = ''; e.currentTarget.style.boxShadow = '0 4px 20px rgba(196,160,122,0.35)' }}
          >
            Search
          </button>
        </div>

        {/* Trending tags */}
        <div style={{ marginTop: '20px', display: 'flex', alignItems: 'center', gap: '8px', flexWrap: 'wrap' }}>
          <span style={{
            fontFamily: "'DM Sans', sans-serif",
            fontSize: '11px', color: 'rgba(212,196,181,0.40)', fontWeight: 500,
            textTransform: 'uppercase', letterSpacing: '0.06em',
          }}>Trending:</span>
          {trending.map(tag => (
            <button key={tag} style={{
              fontFamily: "'DM Sans', sans-serif",
              fontSize: '12px', padding: '5px 11px',
              borderRadius: '8px',
              background: 'rgba(255,255,255,0.05)',
              border: '1px solid rgba(212,196,181,0.18)',
              color: 'rgba(212,196,181,0.65)',
              cursor: 'pointer', fontWeight: 500,
              transition: 'all .15s',
            }}
              onMouseEnter={e => { e.currentTarget.style.background = 'rgba(212,184,150,0.12)'; e.currentTarget.style.color = '#d4b896'; e.currentTarget.style.borderColor = 'rgba(212,184,150,0.35)' }}
              onMouseLeave={e => { e.currentTarget.style.background = 'rgba(255,255,255,0.05)'; e.currentTarget.style.color = 'rgba(212,196,181,0.65)'; e.currentTarget.style.borderColor = 'rgba(212,196,181,0.18)' }}
            >
              {tag}
            </button>
          ))}
        </div>

        {/* Stats row */}
        <div style={{
          marginTop: '48px',
          display: 'flex', gap: '36px',
          paddingTop: '32px',
          borderTop: '1px solid rgba(212,196,181,0.12)',
        }}>
          {[
            { number: '200+', label: 'Open Roles' },
            { number: '80+',  label: 'Companies'  },
            { number: '12k+', label: 'Applicants'  },
          ].map(({ number, label }) => (
            <div key={label}>
              <p style={{
                margin: 0,
                fontSize: '26px', fontWeight: 900,
                color: '#d4b896', lineHeight: 1,
                fontFamily: "'Playfair Display', Georgia, serif",
              }}>{number}</p>
              <p style={{
                margin: '4px 0 0',
                fontSize: '11px', color: 'rgba(212,196,181,0.45)',
                fontFamily: "'DM Sans', sans-serif",
                fontWeight: 500, textTransform: 'uppercase', letterSpacing: '0.07em',
              }}>{label}</p>
            </div>
          ))}
        </div>

      </div>
    </section>
  )
}